class Solution:
    def palindromePartition(self, s: str, k: int) -> int:
        def count_changes(left, right):
            changes = 0
            while left < right:
                if s[left] != s[right]:
                    changes += 1
                left += 1
                right -= 1
            return changes

        memo = {}

        def dp(index, k):
            if (index, k) in memo:
                return memo[(index, k)]
            if k == 1:
                return count_changes(index, len(s) - 1)
            res = float('inf')
            for i in range(index, len(s) - k + 1):
                res = min(res, count_changes(index, i) + dp(i + 1, k - 1))
            memo[(index, k)] = res
            return res

        return dp(0, k)
```
